from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about airports (or related entities) into a single
    fluent sentence. Uses relative clauses to create coherent complex sentences.
    """
    if not triples:
        return ""

    def _clean(val: str) -> str:
        """Remove surrounding quotes if present."""
        return val.strip('"').strip("'")

    def _format_predicate(s: str, p: str, o: str) -> str:
        """Format a triple into natural language."""
        o = _clean(o)

        if p == "cityServed":
            return f"{s} serves the city of {o}"
        elif p == "location":
            return f"{s} is located in {o}"
        elif p == "country":
            return f"{s} is in {o}"
        elif p == "isPartOf":
            return f"{s} is part of {o}"
        elif p == "elevationAboveTheSeaLevel":
            return f"{o} metres above sea level"
        elif p == "elevationAboveTheSeaLevelInFeet":
            return f"{o} feet above sea level"
        elif p == "elevationAboveTheSeaLevelInMetres":
            return f"{o} metres above sea level"
        elif p == "operatingOrganisation":
            return f"operated by {o}"
        elif p == "runwaySurfaceType":
            return f"with runway surface {o}"
        elif p == "runwayName":
            return f"with runway name {o}"
        elif p == "runwayLength":
            return f"with runway length {o}"
        elif p == "iataLocationIdentifier":
            return f"IATA code {o}"
        elif p == "icaoLocationIdentifier":
            return f"ICAO code {o}"
        elif p == "locationIdentifier":
            return f"location identifier {o}"
        elif p.endswith("RunwayLengthFeet"):
            idx = p.split("Runway")[0].lower()
            if idx == "1st":
                return f"with a first runway length of {o} feet"
            elif idx == "2nd":
                return f"with a second runway length of {o} feet"
            elif idx == "3rd":
                return f"with a third runway length of {o} feet"
            elif idx == "4th":
                return f"with a fourth runway length of {o} feet"
            elif idx == "5th":
                return f"with a fifth runway length of {o} feet"
            else:
                return f"with {idx} runway length {o} feet"
        elif p.endswith("RunwayLengthMetre"):
            idx = p.split("Runway")[0].lower()
            if idx == "1st":
                return f"with a first runway length of {o} metres"
            elif idx == "2nd":
                return f"with a second runway length of {o} metres"
            elif idx == "3rd":
                return f"with a third runway length of {o} metres"
            elif idx == "4th":
                return f"with a fourth runway length of {o} metres"
            elif idx == "5th":
                return f"with a fifth runway length of {o} metres"
            else:
                return f"with {idx} runway length {o} metres"
        elif p.endswith("RunwaySurfaceType"):
            idx = p.split("Runway")[0].lower()
            if idx == "1st":
                return f"with a first runway surface of {o}"
            elif idx == "2nd":
                return f"with a second runway surface of {o}"
            elif idx == "3rd":
                return f"with a third runway surface of {o}"
            elif idx == "4th":
                return f"with a fourth runway surface of {o}"
            elif idx == "5th":
                return f"with a fifth runway surface of {o}"
            else:
                return f"with {idx} runway surface {o}"
        elif p.endswith("RunwayNumber"):
            idx = p.split("Runway")[0].lower()
            if idx == "1st":
                return f"with a first runway number of {o}"
            elif idx == "2nd":
                return f"with a second runway number of {o}"
            elif idx == "3rd":
                return f"with a third runway number of {o}"
            elif idx == "4th":
                return f"with a fourth runway number of {o}"
            elif idx == "5th":
                return f"with a fifth runway number of {o}"
            else:
                return f"with {idx} runway number {o}"
        elif p == "nativeName":
            return f"known locally as {o}"
        elif p == "owner":
            return f"owned by {o}"
        elif p == "capital":
            return f"the capital is {o}"
        elif p == "language":
            return f"the language is {o}"
        elif p == "officialLanguage":
            return f"the official language is {o}"
        elif p == "currency":
            return f"the currency is {o}"
        elif p == "demonym":
            return f"the demonym is {o}"
        elif p == "country":
            return f"{s} is in {o}"
        elif p == "isPartOf":
            return f"{s} is part of {o}"
        elif p == "location":
            return f"{s} is located in {o}"
        else:
            return f"with {p.replace('Runway', ' runway').replace('Length', ' length').replace('SurfaceType', ' surface').replace('Number', ' number').replace('Identifier', ' identifier')} {o}"

    # Group triples by subject to build coherent sentences
    subject_triples: dict[str, list[Triple]] = {}
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
        subject_triples[t.subject].append(t)

    # Find the main subject (usually the airport)
    main_subject = triples[0].subject if triples else ""
    other_subjects = [s for s in subject_triples.keys() if s != main_subject]

    # Build the main sentence - prioritize main subject triples
    main_parts = []
    for t in triples:
        if t.subject == main_subject:
            main_parts.append(_format_predicate(t.subject, t.predicate, t.object))

    # Build the sentence with relative clauses
    if main_parts:
        # Start with the first part
        sentence = main_parts[0]

        # Add remaining main subject parts with appropriate connectors
        for i, part in enumerate(main_parts[1:], 1):
            if i == 1:
                sentence += ", " + part
            else:
                sentence += ", and " + part

        # Add information about other subjects with relative clauses
        for other_subj in other_subjects:
            other_triples = subject_triples[other_subj]
            other_parts = [_format_predicate(other_subj, t.predicate, t.object) for t in other_triples]
            if other_parts:
                # Use relative clause to connect - determine the connecting word based on predicate
                connecting_word = "which"
                # Check if this other subject is related to main subject via location/country/isPartOf
                for t in other_triples:
                    if t.predicate in ["country", "isPartOf", "capital"]:
                        connecting_word = "where"
                        break

                sentence += f", {connecting_word} {other_parts[0]}"
                for part in other_parts[1:]:
                    sentence += f", and {part}"

        sentence += "."
        return sentence[0].upper() + sentence[1:]

    return ""

